import type { IGomokuPieceData } from '@kyokuya/react-game-gomoku-core'
import { GomokuPlayerType, GomokuSolution } from '@kyokuya/react-game-gomoku-core'
import type { IPlayer } from './types'

export class CleverComputerPlayer implements IPlayer {
  public readonly type = GomokuPlayerType.COMPUTER

  public async move(
    _GOMOKU_SIZE: number,
    pieces: ReadonlyArray<IGomokuPieceData>,
    playerId: number,
  ): Promise<{ r: number; c: number }> {
    if (pieces.length <= 0) {
      const m: number = _GOMOKU_SIZE >> 1
      return { r: m, c: m }
    }

    const solution = new GomokuSolution(_GOMOKU_SIZE, _GOMOKU_SIZE, undefined, 4)
    solution.init(pieces)
    return solution.minmaxMatch(playerId)
  }
}
