import { useReactiveRef } from '@guanghechen/react-hooks'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import {
  GomokuActionType,
  GomokuContextType,
  GomokuPlayerType,
} from '@kyokuya/react-game-gomoku-core'
import React from 'react'
import { useCurrentPlayer } from './useCurrentPlayer'

export const useMove = (): ((clickedCell?: { r: number; c: number }) => void) => {
  const { state, dispatch } = React.useContext(GomokuContextType)
  const stateRef = useReactiveRef(state)

  const currentPlayerRef = useCurrentPlayer()
  const gameLockRef = React.useRef<boolean>(false)

  const move = React.useCallback(
    (clickedCell?: { r: number; c: number }) => {
      if (gameLockRef.current || !currentPlayerRef.current) return
      if (stateRef.current.gameStatus !== GameRunningStatus.RUNNING) return

      gameLockRef.current = true
      const { GOMOKU_SIZE, pieces, currentPlayerId } = stateRef.current
      currentPlayerRef.current
        .move(GOMOKU_SIZE, pieces, currentPlayerId, clickedCell)
        .then(step => {
          if (step) {
            const { r, c } = step
            if (r >= 0 && r < GOMOKU_SIZE && c >= 0 && c < GOMOKU_SIZE) {
              gameLockRef.current = false
              dispatch({ type: GomokuActionType.MOVE, payload: { r, c } })
            }
          }
        })
        .finally(() => {
          gameLockRef.current = false
        })
    },
    [dispatch, stateRef, currentPlayerRef],
  )

  React.useEffect(() => {
    const player = currentPlayerRef.current
    if (player?.type === GomokuPlayerType.COMPUTER) {
      // Don't stub the canvas drawer.
      setTimeout(move, 0)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [state.currentPlayerId, state.gameStatus])

  return move
}
