import type { IGomokuState } from '@kyokuya/react-game-gomoku-core'
import type { IStorage } from '@kyokuya/react-storage'
import { usePersisDataEffect } from '@kyokuya/react-storage'

const persistKeys: ReadonlyArray<keyof IGomokuState> = [
  'GOMOKU_SIZE',
  'players',
  'winner',
  'instructions',
  'activatedCell',
  'gameTick',
]

export const usePersistGomokuStateEffect = (
  storage: IStorage<Partial<IGomokuState>> | null,
  state: IGomokuState,
): void => {
  usePersisDataEffect<IGomokuState>(storage, state, persistKeys)
}
