import type { IGomokuState } from '@kyokuya/react-game-gomoku-core'
import { GomokuActionType, GomokuContextType } from '@kyokuya/react-game-gomoku-core'
import type { IStorage } from '@kyokuya/react-storage'
import React from 'react'
import { usePersistGomokuStateEffect } from '../hook/usePersistGomokuStateEffect'

export const GamePersistState: React.FC<{
  storage: IStorage<Partial<IGomokuState>> | null
}> = props => {
  const { state, dispatch } = React.useContext(GomokuContextType)
  usePersistGomokuStateEffect(props.storage, state)

  React.useEffect(() => {
    const beforeunload = (): void => dispatch({ type: GomokuActionType.PAUSE })
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [dispatch])

  return <React.Fragment />
}
