import PropTypes from 'prop-types'
import React from 'react'
import type { IGomokuContext } from './context'
import { GomokuContextType } from './context'
import { reducer } from './reducer'
import type { IGomokuState } from './state'
import { initGomokuState } from './state'

export interface IGomokuContextProviderProps {
  /**
   * Initial context data.
   */
  initialState?: Partial<IGomokuState>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const GomokuContextProvider: React.FC<IGomokuContextProviderProps> = props => {
  const { children, initialState } = props
  const [state, dispatch] = React.useReducer(reducer, initialState, initGomokuState)
  const context: IGomokuContext = React.useMemo(() => ({ state, dispatch }), [state, dispatch])
  return <GomokuContextType.Provider value={context}>{children}</GomokuContextType.Provider>
}

GomokuContextProvider.propTypes = {
  initialState: PropTypes.any,
  children: PropTypes.node.isRequired,
}

GomokuContextProvider.displayName = 'GomokuContextProvider'
